function createRenderer() {
  const text = 'HOLOGRAM';
  const slices = 24;

  function clamp(v) { return Math.max(0, Math.min(1, v)); }
  function easeOut(v) { v = clamp(v); return 1 - Math.pow(1 - v, 3); }
  function rand(seed) { const x = Math.sin(seed * 127.1 + 311.7) * 43758.5453; return x - Math.floor(x); }

  function render(t, context) {
    const ctx = context.mainContext;
    const w = context.width;
    const h = context.height;

    // Dark void
    ctx.fillStyle = '#000408';
    ctx.fillRect(0, 0, w, h);

    // Scanlines
    ctx.save();
    ctx.globalAlpha = 0.08;
    for (let y = 0; y < h; y += 3) {
      ctx.fillStyle = y % 6 === 0 ? '#00ffcc' : 'transparent';
      ctx.fillRect(0, y, w, 1);
    }
    ctx.restore();

    // Horizontal scan beam
    const scanY = ((t * 0.4) % 1.2 - 0.1) * h;
    const scanG = ctx.createLinearGradient(0, scanY - 30, 0, scanY + 30);
    scanG.addColorStop(0, 'rgba(0,255,200,0)');
    scanG.addColorStop(0.5, 'rgba(0,255,200,0.15)');
    scanG.addColorStop(1, 'rgba(0,255,200,0)');
    ctx.fillStyle = scanG;
    ctx.fillRect(0, scanY - 30, w, 60);

    const reveal = easeOut(clamp(t / 1.5));
    const glitchIntensity = t > 2 ? Math.sin(t * 20) * 0.5 + 0.5 : 0;

    // Sliced hologram text
    ctx.font = '900 160px "Courier New", monospace';
    const tw = ctx.measureText(text).width;
    const tx = (w - tw) / 2;
    const ty = h * 0.42;
    const sliceH = 160 / slices;

    for (let i = 0; i < slices; i++) {
      const delay = i * 0.04;
      const sp = easeOut(clamp((t - delay) / 0.8));
      if (sp <= 0) continue;

      const sy = ty - 80 + i * sliceH;
      const glitchX = glitchIntensity > 0.7 ? (rand(i + Math.floor(t * 30)) - 0.5) * 40 : 0;
      const glitchY = glitchIntensity > 0.85 ? (rand(i + 99) - 0.5) * 8 : 0;

      ctx.save();
      ctx.globalAlpha = sp * 0.85;
      ctx.beginPath();
      ctx.rect(tx - 20, sy, tw + 40, sliceH + 1);
      ctx.clip();

      // Cyan channel
      ctx.globalAlpha = sp * 0.5;
      ctx.fillStyle = '#00ffff';
      ctx.fillText(text, tx + glitchX - 3, ty + glitchY);

      // Magenta channel
      ctx.fillStyle = '#ff00ff';
      ctx.fillText(text, tx + glitchX + 3, ty + glitchY);

      // Main
      ctx.globalAlpha = sp * 0.9;
      const flicker = 0.7 + 0.3 * Math.sin(t * 15 + i * 2);
      ctx.globalAlpha = sp * flicker;
      ctx.fillStyle = '#e0fff8';
      ctx.fillText(text, tx + glitchX, ty + glitchY);
      ctx.restore();
    }

    // Hologram frame
    const frameA = easeOut(clamp((t - 1) / 0.8));
    ctx.save();
    ctx.globalAlpha = frameA * 0.6;
    ctx.strokeStyle = '#00ffcc';
    ctx.lineWidth = 2;
    const fx = tx - 40, fy = ty - 100, fw = tw + 80, fh = 200;
    ctx.strokeRect(fx, fy, fw, fh);
    // Corner brackets
    const cs = 20;
    ctx.lineWidth = 3;
    [[fx, fy, 1, 1], [fx + fw, fy, -1, 1], [fx, fy + fh, 1, -1], [fx + fw, fy + fh, -1, -1]].forEach(([cx, cy, dx, dy]) => {
      ctx.beginPath();
      ctx.moveTo(cx, cy + dy * cs);
      ctx.lineTo(cx, cy);
      ctx.lineTo(cx + dx * cs, cy);
      ctx.stroke();
    });
    ctx.restore();

    // Data readout
    ctx.save();
    ctx.globalAlpha = easeOut(clamp((t - 2) / 0.6)) * 0.7;
    ctx.font = '400 16px "Courier New", monospace';
    ctx.fillStyle = '#00ffcc';
    const lines = [
      `SCAN: ${Math.floor(t * 100) % 9999}`,
      `SLICE: ${slices}/${slices}`,
      `SIGNAL: ${(85 + Math.sin(t * 5) * 10).toFixed(1)}%`,
      `GLITCH: ${glitchIntensity > 0.5 ? 'DETECTED' : 'NOMINAL'}`,
    ];
    lines.forEach((l, i) => ctx.fillText(l, fx, fy + fh + 30 + i * 22));
    ctx.restore();

    // RGB split flash
    if (glitchIntensity > 0.9) {
      ctx.save();
      ctx.globalAlpha = 0.1;
      ctx.fillStyle = rand(Math.floor(t * 10)) > 0.5 ? '#ff0044' : '#0044ff';
      ctx.fillRect(0, 0, w, h);
      ctx.restore();
    }

    ctx.textAlign = 'center';
    ctx.font = '400 24px Arial, sans-serif';
    ctx.fillStyle = 'rgba(0,255,200,0.5)';
    ctx.fillText('slice displacement · RGB split · scan beam', w / 2, h * 0.78);
  }

  return { render };
}
